type AllocCallback = Option<unsafe extern "C" fn(*mut c_void, usize, u8, usize) -> *mut u8>;
type ResizeCallback =
    Option<unsafe extern "C" fn(*mut c_void, *mut c_void, usize, u8, usize, usize) -> bool>;
type RemapCallback =
    Option<unsafe extern "C" fn(*mut c_void, *mut c_void, usize, u8, usize, usize) -> *mut c_void>;
type FreeCallback = Option<unsafe extern "C" fn(*mut c_void, *mut c_void, usize, u8, usize)>;

#[repr(C)]
pub struct RoasttyAllocatorVtable {
    alloc: AllocCallback,
    resize: ResizeCallback,
    remap: RemapCallback,
    free: FreeCallback,
}

#[repr(C)]
pub struct RoasttyAllocator {
    ctx: *mut c_void,
    vtable: *const RoasttyAllocatorVtable,
}

#[repr(C)]
pub struct RoasttySysImage {
    width: u32,
    height: u32,
    data: *mut u8,
    data_len: usize,
}

type SysLogCallback = unsafe extern "C" fn(*mut c_void, c_int, *const u8, usize, *const u8, usize);
type SysDecodePngCallback = unsafe extern "C" fn(
    *mut c_void,
    *const RoasttyAllocator,
    *const u8,
    usize,
    *mut RoasttySysImage,
) -> bool;

#[derive(Clone, Copy, Debug, Default)]
struct SysState {
    userdata: usize,
    decode_png: Option<SysDecodePngCallback>,
    log: Option<SysLogCallback>,
}

static SYS_STATE: Mutex<SysState> = Mutex::new(SysState {
    userdata: 0,
    decode_png: None,
    log: None,
});

#[cfg(test)]
pub(crate) static SYS_TEST_LOCK: Mutex<()> = Mutex::new(());

static INIT_ARGV: Mutex<Vec<Vec<u8>>> = Mutex::new(Vec::new());

pub(crate) struct DecodedPng {
    pub(crate) width: u32,
    pub(crate) height: u32,
    pub(crate) data: Vec<u8>,
}

static SYS_DECODE_ALLOCATOR_VTABLE: RoasttyAllocatorVtable = RoasttyAllocatorVtable {
    alloc: Some(sys_decode_allocator_alloc),
    resize: None,
    remap: None,
    free: Some(sys_decode_allocator_free),
};

unsafe extern "C" fn sys_decode_allocator_alloc(
    _ctx: *mut c_void,
    len: usize,
    _alignment: u8,
    _ret_addr: usize,
) -> *mut u8 {
    roastty_alloc(ptr::null(), len)
}

unsafe extern "C" fn sys_decode_allocator_free(
    _ctx: *mut c_void,
    ptr: *mut c_void,
    len: usize,
    _alignment: u8,
    _ret_addr: usize,
) {
    roastty_free(ptr::null(), ptr.cast::<u8>(), len);
}

fn sys_decode_allocator() -> RoasttyAllocator {
    RoasttyAllocator {
        ctx: ptr::null_mut(),
        vtable: &SYS_DECODE_ALLOCATOR_VTABLE,
    }
}

pub(crate) fn sys_has_decode_png() -> bool {
    SYS_STATE
        .lock()
        .map(|state| state.decode_png.is_some())
        .unwrap_or(false)
}

pub(crate) fn sys_decode_png(data: &[u8]) -> Result<DecodedPng, ImageLoadError> {
    sys_decode_png_with_limit(data, MAX_IMAGE_SIZE)
}

#[cfg(test)]
pub(crate) fn sys_decode_png_with_limit_for_test(
    data: &[u8],
    max_output_size: usize,
) -> Result<DecodedPng, ImageLoadError> {
    sys_decode_png_with_limit(data, max_output_size)
}

fn sys_decode_png_with_limit(
    data: &[u8],
    max_output_size: usize,
) -> Result<DecodedPng, ImageLoadError> {
    let (userdata, callback) = {
        let state = SYS_STATE.lock().map_err(|_| ImageLoadError::InvalidData)?;
        let callback = state.decode_png.ok_or(ImageLoadError::UnsupportedFormat)?;
        (state.userdata, callback)
    };

    let allocator = sys_decode_allocator();
    let mut output = RoasttySysImage {
        width: 0,
        height: 0,
        data: ptr::null_mut(),
        data_len: 0,
    };
    let ok = unsafe {
        callback(
            userdata as *mut c_void,
            &allocator,
            data.as_ptr(),
            data.len(),
            &mut output,
        )
    };
    if !ok {
        return Err(ImageLoadError::InvalidData);
    }
    if output.data.is_null() {
        return Err(ImageLoadError::InvalidData);
    }
    if output.data_len > max_output_size {
        roastty_free(&allocator, output.data, output.data_len);
        return Err(ImageLoadError::InvalidData);
    }

    let decoded = unsafe { slice::from_raw_parts(output.data, output.data_len) };
    let mut owned = Vec::new();
    let result = owned
        .try_reserve(output.data_len)
        .map_err(|_| ImageLoadError::OutOfMemory)
        .map(|()| {
            owned.extend_from_slice(decoded);
            DecodedPng {
                width: output.width,
                height: output.height,
                data: owned,
            }
        });
    roastty_free(&allocator, output.data, output.data_len);
    result
}

