static VERSION: &[u8] = b"0.1.0-roastty\0";
static EMPTY_STRING: &[u8] = b"\0";
static EMPTY_DIAGNOSTIC: &[u8] = b"\0";
static WINDOW_SAVE_STATE_DEFAULT: &[u8] = b"default\0";
static WINDOW_DECORATION_AUTO: &[u8] = b"auto\0";
static WINDOW_THEME_AUTO: &[u8] = b"auto\0";

fn config_from_handle<'a>(handle: RoasttyConfig) -> Option<&'a mut Config> {
    if handle.is_null() {
        None
    } else {
        Some(unsafe { &mut *(handle.cast::<Config>()) })
    }
}

fn app_from_handle<'a>(handle: RoasttyApp) -> Option<&'a mut App> {
    if handle.is_null() {
        None
    } else {
        Some(unsafe { &mut *(handle.cast::<App>()) })
    }
}

fn surface_from_handle<'a>(handle: RoasttySurface) -> Option<&'a mut Surface> {
    if handle.is_null() {
        None
    } else {
        Some(unsafe { &mut *(handle.cast::<Surface>()) })
    }
}

fn inspector_from_handle<'a>(handle: RoasttyInspector) -> Option<&'a mut Inspector> {
    if handle.is_null() {
        None
    } else {
        Some(unsafe { &mut *(handle.cast::<Inspector>()) })
    }
}

fn register_surface(app: RoasttyApp, surface: NonNull<Surface>) {
    if let Some(app) = app_from_handle(app) {
        app.surfaces.push(surface);
    }
}

fn unregister_surface(app: RoasttyApp, surface: NonNull<Surface>) {
    if let Some(app) = app_from_handle(app) {
        app.surfaces.retain(|registered| *registered != surface);
    }
}

fn copied_config_string(ptr: *const c_char) -> Option<String> {
    if ptr.is_null() {
        return None;
    }
    unsafe { CStr::from_ptr(ptr) }
        .to_str()
        .ok()
        .map(str::to_owned)
}

fn valid_env_key(key: &str) -> bool {
    !key.is_empty() && !key.contains('=')
}

fn valid_surface_context(context: c_int) -> Option<c_int> {
    match context {
        ROASTTY_SURFACE_CONTEXT_WINDOW
        | ROASTTY_SURFACE_CONTEXT_TAB
        | ROASTTY_SURFACE_CONTEXT_SPLIT => Some(context),
        _ => None,
    }
}

fn sanitized_font_size_points(points: f32) -> f32 {
    if points.is_finite() && points > 0.0 {
        points.clamp(1.0, 255.0)
    } else {
        DEFAULT_FONT_SIZE_POINTS
    }
}

fn valid_split_direction(direction: c_int) -> Option<c_int> {
    match direction {
        ROASTTY_SPLIT_DIRECTION_RIGHT
        | ROASTTY_SPLIT_DIRECTION_DOWN
        | ROASTTY_SPLIT_DIRECTION_LEFT
        | ROASTTY_SPLIT_DIRECTION_UP => Some(direction),
        _ => None,
    }
}

