fn signed_storage(value: isize) -> usize {
    value as usize
}

fn goto_tab_action(selector: c_int) -> ParsedBindingAction {
    let mut storage = [0usize; 8];
    storage[0] = signed_storage(selector as isize);
    ParsedBindingAction::RuntimeAction(ROASTTY_ACTION_GOTO_TAB, storage)
}

enum ParsedBindingAction {
    RuntimeAction(c_int, [usize; 8]),
    AppRuntimeAction(c_int, [usize; 8]),
    StartSearch,
    SearchSelection,
    CopyUrlToClipboard,
    WriteFile(WriteFileTarget, WriteFileAction, WriteFileFormat),
    CloseSurface,
    Text(Vec<u8>),
    Csi(Vec<u8>),
    Esc(Vec<u8>),
    PromptTitle(c_int),
    SetTitle(c_int, Vec<u8>),
    Reset,
    ClearScreen,
    SelectAll,
    AdjustSelection(TerminalSelectionAdjustment),
    CopyToClipboard(CopyToClipboardFormat),
    PasteFromClipboard(c_int),
    IncreaseFontSize(f32),
    DecreaseFontSize(f32),
    ResetFontSize,
    SetFontSize(f32),
    ScrollToTop,
    ScrollToBottom,
    ScrollToRow(usize),
    ScrollToSelection,
    ScrollPageUp,
    ScrollPageDown,
    ScrollPageLines(i16),
    ScrollPageFractional(f32),
    JumpToPrompt(i16),
    ToggleMouseReporting,
    ToggleReadonly,
}

fn parameterless_app_action(parameter: Option<&[u8]>, tag: c_int) -> Option<ParsedBindingAction> {
    if parameter.is_some() {
        return None;
    }
    Some(ParsedBindingAction::AppRuntimeAction(tag, [0usize; 8]))
}

