fn parse_u16_ascii(bytes: &[u8]) -> Option<u16> {
    if bytes.is_empty() {
        return None;
    }
    let mut value: u32 = 0;
    for byte in bytes {
        if !byte.is_ascii_digit() {
            return None;
        }
        value = value
            .saturating_mul(10)
            .saturating_add(u32::from(byte - b'0'));
        if value > u32::from(u16::MAX) {
            return None;
        }
    }
    Some(value as u16)
}

fn parse_usize_ascii(bytes: &[u8]) -> Option<usize> {
    let digits = match bytes.first()? {
        b'+' => &bytes[1..],
        _ => bytes,
    };
    if digits.is_empty() {
        return None;
    }

    let mut value: usize = 0;
    for byte in digits {
        if !byte.is_ascii_digit() {
            return None;
        }
        value = value.checked_mul(10)?;
        value = value.checked_add(usize::from(byte - b'0'))?;
    }
    Some(value)
}

fn parse_i16_ascii(bytes: &[u8]) -> Option<i16> {
    let (sign, digits) = match bytes.first()? {
        b'+' => (1i32, &bytes[1..]),
        b'-' => (-1i32, &bytes[1..]),
        _ => (1i32, bytes),
    };
    if digits.is_empty() {
        return None;
    }

    let mut magnitude: i32 = 0;
    for byte in digits {
        if !byte.is_ascii_digit() {
            return None;
        }
        magnitude = magnitude
            .saturating_mul(10)
            .saturating_add(i32::from(byte - b'0'));
        if sign == 1 && magnitude > i32::from(i16::MAX) {
            return None;
        }
        if sign == -1 && magnitude > i32::from(i16::MAX) + 1 {
            return None;
        }
    }

    i16::try_from(sign * magnitude).ok()
}

fn parse_isize_ascii(bytes: &[u8]) -> Option<isize> {
    if bytes.is_empty() || bytes.iter().any(u8::is_ascii_whitespace) {
        return None;
    }
    std::str::from_utf8(bytes).ok()?.parse().ok()
}

fn parse_f32_ascii(bytes: &[u8]) -> Option<f32> {
    if bytes.is_empty() || bytes.iter().any(u8::is_ascii_whitespace) {
        return None;
    }
    let text = std::str::from_utf8(bytes).ok()?;
    let value: f32 = text.parse().ok()?;
    if !value.is_finite() {
        return None;
    }
    let max_fraction = isize::MAX as f64 / f64::from(u16::MAX);
    if f64::from(value).abs() > max_fraction {
        return None;
    }
    Some(value)
}

fn parse_font_size_f32_ascii(bytes: &[u8]) -> Option<f32> {
    if bytes.is_empty() || bytes.iter().any(u8::is_ascii_whitespace) {
        return None;
    }
    let text = std::str::from_utf8(bytes).ok()?;
    let value: f32 = text.parse().ok()?;
    if value.is_finite() {
        Some(value)
    } else {
        None
    }
}

fn parse_title_bytes(bytes: &[u8]) -> Option<Vec<u8>> {
    if bytes.contains(&0) || std::str::from_utf8(bytes).is_err() {
        return None;
    }
    Some(bytes.to_vec())
}

fn copied_env_vars(ptr: *mut RoasttyEnvVar, len: usize) -> Vec<(String, String)> {
    if ptr.is_null() || len == 0 {
        return Vec::new();
    }

    let vars = unsafe { slice::from_raw_parts(ptr, len) };
    vars.iter()
        .filter_map(|var| {
            let key = copied_config_string(var.key)?;
            if !valid_env_key(&key) {
                return None;
            }
            let value = copied_config_string(var.value)?;
            Some((key, value))
        })
        .collect()
}

