#[no_mangle]
pub extern "C" fn roastty_config_get(
    config: RoasttyConfig,
    output: *mut c_void,
    key: *const c_char,
    key_len: usize,
) -> bool {
    if config.is_null() || output.is_null() || key.is_null() {
        return false;
    }

    let key = unsafe { slice::from_raw_parts(key.cast::<u8>(), key_len) };
    unsafe {
        match key {
            b"initial-window" => {
                output.cast::<bool>().write(true);
                true
            }
            b"quit-after-last-window-closed" => {
                output.cast::<bool>().write(false);
                true
            }
            b"window-save-state" => {
                output
                    .cast::<*const c_char>()
                    .write(WINDOW_SAVE_STATE_DEFAULT.as_ptr().cast());
                true
            }
            b"window-decoration" => {
                output
                    .cast::<*const c_char>()
                    .write(WINDOW_DECORATION_AUTO.as_ptr().cast());
                true
            }
            b"window-theme" => {
                output
                    .cast::<*const c_char>()
                    .write(WINDOW_THEME_AUTO.as_ptr().cast());
                true
            }
            b"background-opacity" => {
                output.cast::<f64>().write(1.0);
                true
            }
            b"bell-audio-volume" => {
                output.cast::<f64>().write(0.5);
                true
            }
            b"notify-on-command-finish-after" => {
                output.cast::<usize>().write(5000);
                true
            }
            b"title" => {
                output.cast::<*const c_char>().write(ptr::null());
                true
            }
            b"window-position-x" | b"window-position-y" | b"bell-audio-path" => false,
            _ => false,
        }
    }
}

#[no_mangle]
pub extern "C" fn roastty_config_trigger(
    config: RoasttyConfig,
    action: *const c_char,
    action_len: usize,
) -> RoasttyInputTrigger {
    let Some(config) = config_from_handle(config) else {
        return empty_trigger();
    };
    if action.is_null() {
        return empty_trigger();
    }
    let action = unsafe { slice::from_raw_parts(action.cast::<u8>(), action_len) };
    if let Some(binding) = config
        .keybind_triggers
        .iter()
        .rev()
        .find(|binding| binding.action.as_slice() == action)
    {
        return binding.trigger;
    }
    default_config_trigger(action)
}

#[no_mangle]
pub extern "C" fn roastty_config_key_is_binding(
    config: RoasttyConfig,
    event: RoasttyKeyEvent,
) -> bool {
    let Some(config) = config_from_handle(config) else {
        return false;
    };
    let Some(event) = key_event_from_handle(event) else {
        return false;
    };
    if config.key_event_is_binding(&event.event) {
        return true;
    }
    default_key_event_is_binding(&event.event)
}

