#[no_mangle]
pub extern "C" fn roastty_app_new(
    runtime: *const RoasttyRuntimeConfig,
    config: RoasttyConfig,
) -> RoasttyApp {
    let runtime = if runtime.is_null() {
        RoasttyRuntimeConfig {
            userdata: ptr::null_mut(),
            supports_selection_clipboard: false,
            wakeup_cb: None,
            action_cb: None,
            read_clipboard_cb: None,
            confirm_read_clipboard_cb: None,
            write_clipboard_cb: None,
            close_surface_cb: None,
        }
    } else {
        unsafe { *runtime }
    };
    let (confirm_close_surface, has_global_keybinds, keybind_triggers) = config_from_handle(config)
        .map(|config| {
            (
                config.confirm_close_surface,
                config.has_global_keybinds,
                config.keybind_triggers.clone(),
            )
        })
        .unwrap_or((config::ConfirmCloseSurface::True, false, Vec::new()));

    Box::into_raw(Box::new(App {
        runtime,
        focused: false,
        color_scheme: 0,
        confirm_close_surface,
        has_global_keybinds,
        keybind_triggers,
        surfaces: Vec::new(),
    }))
    .cast()
}

#[no_mangle]
pub extern "C" fn roastty_app_free(app: RoasttyApp) {
    if !app.is_null() {
        unsafe {
            let mut app_box = Box::from_raw(app.cast::<App>());
            for mut surface in app_box.surfaces.drain(..) {
                let surface = surface.as_mut();
                surface.app = ptr::null_mut();
                surface.termio_worker = None;
            }
            drop(app_box);
        }
    }
}

#[no_mangle]
pub extern "C" fn roastty_app_tick(app: RoasttyApp) {
    let surfaces = app_from_handle(app)
        .map(|app| app.surfaces.clone())
        .unwrap_or_default();
    for mut surface in surfaces {
        let surface = unsafe { surface.as_mut() };
        if surface.app == app {
            surface.tick_termio();
        }
    }
}

