pub extern "C" fn roastty_surface_text(surface: RoasttySurface, text: *const c_char, len: usize) {
    if len == 0 {
        return;
    }
    if text.is_null() {
        return;
    }
    if let Some(surface) = surface_from_handle(surface) {
        let bytes = unsafe { slice::from_raw_parts(text.cast::<u8>(), len) };
        surface.text(bytes);
    }
}

#[no_mangle]
pub extern "C" fn roastty_surface_preedit(
    surface: RoasttySurface,
    preedit: *const c_char,
    len: usize,
) {
    let Some(surface) = surface_from_handle(surface) else {
        return;
    };
    if len == 0 {
        surface.set_preedit(None);
        return;
    }
    if preedit.is_null() {
        return;
    }

    let bytes = unsafe { slice::from_raw_parts(preedit.cast::<u8>(), len) };
    surface.set_preedit(std::str::from_utf8(bytes).ok());
}

#[no_mangle]
pub extern "C" fn roastty_surface_ime_point(
    surface: RoasttySurface,
    x: *mut f64,
    y: *mut f64,
    width: *mut f64,
    height: *mut f64,
) {
    let point = surface_from_handle(surface)
        .map(|surface| surface.ime_point())
        .unwrap_or_default();
    unsafe {
        if !x.is_null() {
            x.write(point.x);
        }
        if !y.is_null() {
            y.write(point.y);
        }
        if !width.is_null() {
            width.write(point.width);
        }
        if !height.is_null() {
            height.write(point.height);
        }
    }
}

#[no_mangle]
pub extern "C" fn roastty_surface_complete_clipboard_request(
    surface: RoasttySurface,
    text: *const c_char,
    state: *mut c_void,
    confirmed: bool,
) {
    if text.is_null() || state != surface || !confirmed {
        return;
    }
    let Some(surface) = surface_from_handle(surface) else {
        return;
    };
    if surface.app.is_null() || surface.termio_worker.is_none() {
        return;
    }
    let bytes = unsafe { CStr::from_ptr(text) }.to_bytes();
    surface.text(bytes);
}

