    fn c_str_ptr_to_str(ptr: *const c_char) -> Option<String> {
        if ptr.is_null() {
            None
        } else {
            Some(unsafe { CStr::from_ptr(ptr) }.to_str().unwrap().to_string())
        }
    }

    fn take_roastty_text(mut text: RoasttyText) -> Vec<u8> {
        if text.text.is_null() {
            return Vec::new();
        }
        let bytes = unsafe { slice::from_raw_parts(text.text.cast::<u8>(), text.text_len) };
        let out = bytes.to_vec();
        assert_eq!(unsafe { *text.text.add(text.text_len) }, 0);
        roastty_surface_free_text(ptr::null_mut(), &mut text);
        assert!(text.text.is_null());
        assert_eq!(text.text_len, 0);
        out
    }

    fn surface_snapshot_text_after_start(app: RoasttyApp, surface: RoasttySurface) -> String {
        assert_eq!(roastty_surface_start(surface), ROASTTY_SUCCESS);
        surface_snapshot_text(app, surface)
    }

    fn surface_snapshot_text(app: RoasttyApp, surface: RoasttySurface) -> String {
        wait_until(|| {
            roastty_app_tick(app);
            roastty_surface_needs_render(surface)
        });
        let state = new_render_state();
        assert_eq!(
            roastty_surface_render_state_update(surface, state),
            ROASTTY_SUCCESS
        );
        let text = render_state_text(state);
        roastty_render_state_free(state);
        text
    }

    fn surface_snapshot_text_until(
        app: RoasttyApp,
        surface: RoasttySurface,
        needle: &str,
    ) -> String {
        let mut latest = String::new();
        for _ in 0..300 {
            roastty_app_tick(app);
            if roastty_surface_needs_render(surface) {
                let state = new_render_state();
                assert_eq!(
                    roastty_surface_render_state_update(surface, state),
                    ROASTTY_SUCCESS
                );
                latest = render_state_text(state);
                roastty_render_state_free(state);
                if latest.contains(needle) {
                    return latest;
                }
            }
            thread::sleep(Duration::from_millis(10));
        }
        panic!("condition not met, latest snapshot: {latest:?}");
    }

