    #[test]
    fn surface_key_is_binding_matches_app_configured_keybinds_after_config_free() {
        with_init_args(
            &[
                "roastty",
                "--keybind=cmd+KeyN=new_window",
                "--keybind=ctrl+x=text:custom",
                "--keybind=alt+z=text:unshifted",
            ],
            || {
                let config = roastty_config_new();
                roastty_config_load_cli_args(config);
                let app = roastty_app_new(ptr::null(), config);
                roastty_config_free(config);
                let surface = new_test_surface(app);
                let event = new_key_event();
                let mut flags = 0xffu8;

                set_key_event(
                    event,
                    key::KeyAction::Press,
                    key::Key::KeyN,
                    ROASTTY_MODS_SUPER,
                    &[],
                    0,
                );
                assert!(roastty_surface_key_is_binding(surface, event, &mut flags));
                assert_eq!(flags, ROASTTY_KEYBIND_FLAGS_DEFAULT);

                flags = 0xff;
                set_key_event(
                    event,
                    key::KeyAction::Press,
                    key::Key::Unidentified,
                    ROASTTY_MODS_CTRL,
                    b"x",
                    0,
                );
                assert!(roastty_surface_key_is_binding(surface, event, &mut flags));
                assert_eq!(flags, ROASTTY_KEYBIND_FLAGS_DEFAULT);

                flags = 0xff;
                set_key_event(
                    event,
                    key::KeyAction::Press,
                    key::Key::Unidentified,
                    ROASTTY_MODS_ALT,
                    &[],
                    u32::from(b'z'),
                );
                assert!(roastty_surface_key_is_binding(surface, event, &mut flags));
                assert_eq!(flags, ROASTTY_KEYBIND_FLAGS_DEFAULT);

                set_key_event(
                    event,
                    key::KeyAction::Press,
                    key::Key::KeyN,
                    ROASTTY_MODS_SUPER,
                    &[],
                    0,
                );
                assert!(roastty_surface_key_is_binding(
                    surface,
                    event,
                    ptr::null_mut()
                ));

                set_key_event(
                    event,
                    key::KeyAction::Release,
                    key::Key::KeyN,
                    ROASTTY_MODS_SUPER,
                    &[],
                    0,
                );
                flags = 0xff;
                assert!(!roastty_surface_key_is_binding(surface, event, &mut flags));
                assert_eq!(flags, 0);

                set_key_event(
                    event,
                    key::KeyAction::Press,
                    key::Key::KeyN,
                    ROASTTY_MODS_CTRL,
                    &[],
                    0,
                );
                flags = 0xff;
                assert!(!roastty_surface_key_is_binding(surface, event, &mut flags));
                assert_eq!(flags, 0);

                roastty_app_free(app);
                set_key_event(
                    event,
                    key::KeyAction::Press,
                    key::Key::KeyN,
                    ROASTTY_MODS_SUPER,
                    &[],
                    0,
                );
                flags = 0xff;
                assert!(!roastty_surface_key_is_binding(surface, event, &mut flags));
                assert_eq!(flags, 0);

                roastty_key_event_free(event);
                roastty_surface_free(surface);
            },
        );
    }

