    #[test]
    fn keybind_trigger_abi_layout_and_empty_values_are_stable() {
        assert_eq!(
            std::mem::size_of::<RoasttyInputTrigger>(),
            std::mem::size_of::<c_int>() * 3
        );
        assert_eq!(std::mem::offset_of!(RoasttyInputTrigger, tag), 0);
        assert_eq!(
            std::mem::offset_of!(RoasttyInputTrigger, key),
            std::mem::size_of::<c_int>()
        );
        assert_eq!(
            std::mem::offset_of!(RoasttyInputTrigger, mods),
            std::mem::size_of::<c_int>() * 2
        );

        let trigger = empty_trigger();
        assert_eq!(trigger.tag, ROASTTY_TRIGGER_PHYSICAL);
        assert_eq!(
            unsafe { trigger.key.physical },
            key::Key::Unidentified as c_int
        );
        assert_eq!(trigger.mods, ROASTTY_MODS_NONE);
    }

    fn assert_empty_config_trigger(trigger: RoasttyInputTrigger) {
        assert_eq!(trigger.tag, ROASTTY_TRIGGER_PHYSICAL);
        assert_eq!(
            unsafe { trigger.key.physical },
            key::Key::Unidentified as c_int
        );
        assert_eq!(trigger.mods, ROASTTY_MODS_NONE);
    }

    fn assert_physical_config_trigger(trigger: RoasttyInputTrigger, key: key::Key, mods: c_int) {
        assert_eq!(trigger.tag, ROASTTY_TRIGGER_PHYSICAL);
        assert_eq!(unsafe { trigger.key.physical }, key as c_int);
        assert_eq!(trigger.mods, mods);
    }

    fn assert_unicode_config_trigger(trigger: RoasttyInputTrigger, codepoint: u32, mods: c_int) {
        assert_eq!(trigger.tag, ROASTTY_TRIGGER_UNICODE);
        assert_eq!(unsafe { trigger.key.unicode }, codepoint);
        assert_eq!(trigger.mods, mods);
    }

    fn with_init_args(args: &[&str], f: impl FnOnce()) {
        let _guard = CLI_ARGS_LOCK.lock().unwrap();
        let strings = args
            .iter()
            .map(|arg| CString::new(*arg).unwrap())
            .collect::<Vec<_>>();
        let mut ptrs = strings
            .iter()
            .map(|arg| arg.as_ptr().cast_mut())
            .collect::<Vec<_>>();
        assert_eq!(roastty_init(ptrs.len(), ptrs.as_mut_ptr()), ROASTTY_SUCCESS);
        f();
        assert_eq!(roastty_init(0, ptr::null_mut()), ROASTTY_SUCCESS);
    }

