    #[test]
    fn surface_pty_size_uses_fallbacks_and_clamps_pixels() {
        let app = new_test_app();
        let surface = new_test_surface(app);
        let surface_ref = surface_from_handle(surface).unwrap();

        assert_eq!(
            surface_ref.pty_size(),
            os::pty::PtySize {
                rows: 24,
                cols: 80,
                width_px: 0,
                height_px: 0,
            }
        );

        surface_ref.size.rows = 0;
        surface_ref.size.columns = 120;
        surface_ref.size.width_px = 70_000;
        surface_ref.size.height_px = 42;
        assert_eq!(
            surface_ref.pty_size(),
            os::pty::PtySize {
                rows: 24,
                cols: 120,
                width_px: u16::MAX,
                height_px: 42,
            }
        );

        surface_ref.size.rows = 33;
        surface_ref.size.columns = 0;
        assert_eq!(surface_ref.pty_size().rows, 33);
        assert_eq!(surface_ref.pty_size().cols, 80);

        roastty_surface_free(surface);
        roastty_app_free(app);
    }

    unsafe extern "C" fn write_pty_cb(
        terminal: RoasttyTerminal,
        userdata: *mut c_void,
        ptr: *const u8,
        len: usize,
    ) {
        let bytes = if ptr.is_null() || len == 0 {
            Vec::new()
        } else {
            slice::from_raw_parts(ptr, len).to_vec()
        };
        with_effect_state(|state| {
            state.last_terminal = terminal;
            state.last_userdata = userdata;
            state.write_calls.push(bytes);
        });
    }

    unsafe extern "C" fn bell_cb(terminal: RoasttyTerminal, userdata: *mut c_void) {
        with_effect_state(|state| {
            state.last_terminal = terminal;
            state.last_userdata = userdata;
            state.bell_count += 1;
        });
    }

    unsafe extern "C" fn enquiry_cb(
        terminal: RoasttyTerminal,
        userdata: *mut c_void,
    ) -> RoasttyString {
        with_effect_state(|state| {
            state.last_terminal = terminal;
            state.last_userdata = userdata;
            RoasttyString {
                ptr: state.enquiry_ptr,
                len: state.enquiry_len,
                sentinel: false,
            }
        })
    }

    unsafe extern "C" fn xtversion_cb(
        terminal: RoasttyTerminal,
        userdata: *mut c_void,
    ) -> RoasttyString {
        with_effect_state(|state| {
            state.last_terminal = terminal;
            state.last_userdata = userdata;
            RoasttyString {
                ptr: state.xtversion_ptr,
                len: state.xtversion_len,
                sentinel: false,
            }
        })
    }

    unsafe extern "C" fn title_changed_cb(terminal: RoasttyTerminal, userdata: *mut c_void) {
        with_effect_state(|state| {
            state.last_terminal = terminal;
            state.last_userdata = userdata;
            state.title_changed_count += 1;
        });
    }

    unsafe extern "C" fn size_cb(
        terminal: RoasttyTerminal,
        userdata: *mut c_void,
        out_size: *mut size_report::Size,
    ) -> bool {
        with_effect_state(|state| {
            state.last_terminal = terminal;
            state.last_userdata = userdata;
            state.size_count += 1;
            if state.size_result && !out_size.is_null() {
                out_size.write(state.size_response);
            }
            state.size_result
        })
    }

