    fn write_kitty_transmit_display(
        terminal: RoasttyTerminal,
        image_id: u32,
        placement_id: u32,
        z: i32,
    ) {
        write_terminal(
            terminal,
            format!(
                "\x1b_Ga=T,f=32,s=1,v=1,i={image_id},p={placement_id},x=2,y=3,w=4,h=5,X=6,Y=7,c=3,r=2,z={z},C=1;AQIDBA==\x1b\\"
            )
            .as_bytes(),
        );
        let _ = terminal_string(terminal, roastty_terminal_take_pty_response);
    }

    #[derive(Clone, Copy)]
    struct KittyDisplayFixture {
        image_id: u32,
        placement_id: u32,
        image_width: u32,
        image_height: u32,
        source_x: u32,
        source_y: u32,
        source_width: u32,
        source_height: u32,
        x_offset: u32,
        y_offset: u32,
        columns: u32,
        rows: u32,
        z: i32,
    }

    fn kitty_rgba_payload(width: u32, height: u32) -> &'static str {
        match width.saturating_mul(height).saturating_mul(4) {
            4 => "AQIDBA==",
            32 => "AQIDBAUGBwgJCgsMDQ4PEBESExQVFhcYGRobHB0eHyA=",
            64 => {
                "AQIDBAUGBwgJCgsMDQ4PEBESExQVFhcYGRobHB0eHyAhIiMkJSYnKCkqKywtLi8wMTIzNDU2Nzg5Ojs8PT4/QA=="
            }
            other => panic!("missing Kitty RGBA payload for {other} bytes"),
        }
    }

    fn write_kitty_fixture(terminal: RoasttyTerminal, fixture: KittyDisplayFixture) {
        write_terminal(
            terminal,
            format!(
                "\x1b_Ga=T,f=32,s={},v={},i={},p={},x={},y={},w={},h={},X={},Y={},c={},r={},z={},C=1;{}\x1b\\",
                fixture.image_width,
                fixture.image_height,
                fixture.image_id,
                fixture.placement_id,
                fixture.source_x,
                fixture.source_y,
                fixture.source_width,
                fixture.source_height,
                fixture.x_offset,
                fixture.y_offset,
                fixture.columns,
                fixture.rows,
                fixture.z,
                kitty_rgba_payload(fixture.image_width, fixture.image_height)
            )
            .as_bytes(),
        );
        let _ = terminal_string(terminal, roastty_terminal_take_pty_response);
    }

    fn write_kitty_virtual_fixture(terminal: RoasttyTerminal, fixture: KittyDisplayFixture) {
        write_terminal(
            terminal,
            format!(
                "\x1b_Ga=T,f=32,s={},v={},i={},p={},U=1,x={},y={},w={},h={},X={},Y={},c={},r={},z={},C=1;{}\x1b\\",
                fixture.image_width,
                fixture.image_height,
                fixture.image_id,
                fixture.placement_id,
                fixture.source_x,
                fixture.source_y,
                fixture.source_width,
                fixture.source_height,
                fixture.x_offset,
                fixture.y_offset,
                fixture.columns,
                fixture.rows,
                fixture.z,
                kitty_rgba_payload(fixture.image_width, fixture.image_height)
            )
            .as_bytes(),
        );
        let _ = terminal_string(terminal, roastty_terminal_take_pty_response);
    }

    fn write_kitty_placeholder(
        terminal: RoasttyTerminal,
        image_id: u32,
        placement_id: Option<u32>,
        row: Option<u32>,
        col: Option<u32>,
        width: usize,
    ) {
        let r = (image_id >> 16) & 0xff;
        let g = (image_id >> 8) & 0xff;
        let b = image_id & 0xff;
        write_terminal(terminal, format!("\x1b[38;2;{r};{g};{b}m").as_bytes());
        if let Some(placement_id) = placement_id {
            let r = (placement_id >> 16) & 0xff;
            let g = (placement_id >> 8) & 0xff;
            let b = placement_id & 0xff;
            write_terminal(terminal, format!("\x1b[58;2;{r};{g};{b}m").as_bytes());
        }
        let row_mark = match row {
            Some(0) => "\u{0305}",
            Some(1) => "\u{030d}",
            Some(2) => "\u{030e}",
            Some(value) => panic!("unsupported test row mark {value}"),
            None => "",
        };
        let col_mark = match col {
            Some(0) => "\u{0305}",
            Some(1) => "\u{030d}",
            Some(2) => "\u{030e}",
            Some(value) => panic!("unsupported test col mark {value}"),
            None => "",
        };
        let first = format!("\u{10eeee}{row_mark}{col_mark}");
        write_terminal(terminal, first.as_bytes());
        for _ in 1..width {
            write_terminal(terminal, "\u{10eeee}".as_bytes());
        }
        write_terminal(terminal, b"\x1b[0m");
    }

