    fn packed_cell(tag: c_int, content: u64) -> RoasttyCell {
        (tag as u64) | (content << 2)
    }

    fn packed_cell_with_flags(
        mut cell: RoasttyCell,
        style_id: u16,
        wide: c_int,
        protected: bool,
        hyperlink: bool,
        semantic: c_int,
    ) -> RoasttyCell {
        cell |= (style_id as u64) << 26;
        cell |= (wide as u64) << 42;
        if protected {
            cell |= 1_u64 << 44;
        }
        if hyperlink {
            cell |= 1_u64 << 45;
        }
        cell | ((semantic as u64) << 46)
    }

    #[allow(clippy::too_many_arguments)]
    fn packed_row(
        wrap: bool,
        wrap_continuation: bool,
        grapheme: bool,
        styled: bool,
        hyperlink: bool,
        semantic_prompt: c_int,
        kitty_virtual_placeholder: bool,
        dirty: bool,
    ) -> RoasttyRow {
        let mut row = 0_u64;
        if wrap {
            row |= 1_u64 << 32;
        }
        if wrap_continuation {
            row |= 1_u64 << 33;
        }
        if grapheme {
            row |= 1_u64 << 34;
        }
        if styled {
            row |= 1_u64 << 35;
        }
        if hyperlink {
            row |= 1_u64 << 36;
        }
        row |= (semantic_prompt as u64) << 37;
        if kitty_virtual_placeholder {
            row |= 1_u64 << 39;
        }
        if dirty {
            row |= 1_u64 << 40;
        }
        row
    }

