    #[test]
    fn row_c_abi_validates_inputs_and_multi_reports_progress() {
        let row = packed_row(
            true,
            false,
            false,
            false,
            false,
            ROASTTY_ROW_SEMANTIC_PROMPT,
            false,
            true,
        );
        let mut wrap = false;
        assert_eq!(
            roastty_row_get(
                row,
                ROASTTY_ROW_DATA_INVALID,
                &mut wrap as *mut _ as *mut c_void
            ),
            ROASTTY_INVALID_VALUE
        );
        assert_eq!(
            roastty_row_get(row, ROASTTY_ROW_DATA_WRAP, ptr::null_mut()),
            ROASTTY_INVALID_VALUE
        );
        assert_eq!(
            roastty_row_get(row, 99, &mut wrap as *mut _ as *mut c_void),
            ROASTTY_INVALID_VALUE
        );

        let mut dirty = false;
        let keys = [ROASTTY_ROW_DATA_WRAP, ROASTTY_ROW_DATA_DIRTY];
        let mut values = [
            &mut wrap as *mut _ as *mut c_void,
            &mut dirty as *mut _ as *mut c_void,
        ];
        let mut written = 99usize;
        assert_eq!(
            roastty_row_get_multi(
                row,
                keys.len(),
                keys.as_ptr(),
                values.as_mut_ptr(),
                &mut written,
            ),
            ROASTTY_SUCCESS
        );
        assert_eq!(written, 2);
        assert!(wrap);
        assert!(dirty);
        assert_eq!(
            roastty_row_get_multi(row, 0, keys.as_ptr(), values.as_mut_ptr(), &mut written),
            ROASTTY_SUCCESS
        );
        assert_eq!(written, 0);
        assert_eq!(
            roastty_row_get_multi(
                row,
                keys.len(),
                ptr::null(),
                values.as_mut_ptr(),
                &mut written
            ),
            ROASTTY_INVALID_VALUE
        );
        assert_eq!(written, 0);

        let partial_keys = [ROASTTY_ROW_DATA_WRAP, ROASTTY_ROW_DATA_INVALID];
        written = 99;
        assert_eq!(
            roastty_row_get_multi(
                row,
                partial_keys.len(),
                partial_keys.as_ptr(),
                values.as_mut_ptr(),
                &mut written,
            ),
            ROASTTY_INVALID_VALUE
        );
        assert_eq!(written, 1);
        assert_eq!(
            roastty_row_get_multi(
                row,
                partial_keys.len(),
                partial_keys.as_ptr(),
                values.as_mut_ptr(),
                ptr::null_mut(),
            ),
            ROASTTY_INVALID_VALUE
        );
    }

